  1→"use client";
  2→
  3→import { useEffect, useState, useCallback } from "react";
  4→import {
  5→  Phone,
  6→  Calendar,
  7→  Mail,
  8→  FileText,
  9→  CheckSquare,
 10→  Loader2,
 11→  AlertCircle,
 12→  MessageSquare,
 13→} from "lucide-react";
 14→import { Card, CardContent } from "@/components/ui/card";
 15→import { Badge } from "@/components/ui/badge";
 16→import { Button } from "@/components/ui/button";
 17→import { getContactInteractions } from "@/lib/api/interactions";
 18→import { ApiClientError } from "@/lib/api/shared";
 19→
 20→interface TimelineAuthor {
 21→  name: string;
 22→}
 23→
 24→interface TimelineItem {
 25→  id: string;
 26→  type: string;
 27→  direction?: string | null;
 28→  subject?: string | null;
 29→  content?: string | null;
 30→  scheduledAt?: string | null;
 31→  completedAt?: string | null;
 32→  createdAt: string;
 33→  author?: TimelineAuthor | null;
 34→}
 35→
 36→const typeConfig: Record<
 37→  string,
 38→  { icon: React.ComponentType<{ className?: string }>; label: string; variant: "default" | "secondary" | "outline" | "ghost" }
 39→> = {
 40→  call: { icon: Phone, label: "Call", variant: "default" },
 41→  meeting: { icon: Calendar, label: "Meeting", variant: "secondary" },
 42→  email: { icon: Mail, label: "Email", variant: "outline" },
 43→  note: { icon: FileText, label: "Note", variant: "ghost" },
 44→  task: { icon: CheckSquare, label: "Task", variant: "outline" },
 45→};
 46→
 47→const defaultTypeConfig = {
 48→  icon: MessageSquare,
 49→  label: "Interaction",
 50→  variant: "outline" as const,
 51→};
 52→
 53→function formatDate(dateStr: string): string {
 54→  return new Intl.DateTimeFormat("en-US", {
 55→    month: "short",
 56→    day: "numeric",
 57→    year: "numeric",
 58→    hour: "numeric",
 59→    minute: "2-digit",
 60→  }).format(new Date(dateStr));
 61→}
 62→
 63→function contentPreview(content: string | null | undefined, maxLen = 120): string | null {
 64→  if (!content) return null;
 65→  if (content.length <= maxLen) return content;
 66→  return content.slice(0, maxLen) + "…";
 67→}
 68→
 69→interface InteractionTimelineProps {
 70→  contactId: string;
 71→}
 72→
 73→export function InteractionTimeline({ contactId }: InteractionTimelineProps) {
 74→  const [items, setItems] = useState<TimelineItem[] | null>(null);
 75→  const [loading, setLoading] = useState(true);
 76→  const [error, setError] = useState<string | null>(null);
 77→
 78→  const fetchTimeline = useCallback(async () => {
 79→    setLoading(true);
 80→    setError(null);
 81→    try {
 82→      const response = await getContactInteractions(contactId);
 83→      setItems(response.data as unknown as TimelineItem[]);
 84→    } catch (err) {
 85→      const message =
 86→        err instanceof ApiClientError ? err.message : "Failed to load interactions";
 87→      console.error("InteractionTimeline fetch error:", err);
 88→      setError(message);
 89→    } finally {
 90→      setLoading(false);
 91→    }
 92→  }, [contactId]);
 93→
 94→  useEffect(() => {
 95→    fetchTimeline();
 96→  }, [fetchTimeline]);
 97→
 98→  if (loading) {
 99→    return (
100→      <div className="flex items-center justify-center py-12 text-muted-foreground">
101→        <Loader2 className="mr-2 size-4 animate-spin" />
102→        Loading interactions…
103→      </div>
104→    );
105→  }
106→
107→  if (error) {
108→    return (
109→      <div className="flex flex-col items-center gap-3 py-12">
110→        <div className="flex items-center gap-2 text-destructive">
111→          <AlertCircle className="size-4" />
112→          <span className="text-sm">{error}</span>
113→        </div>
114→        <Button variant="outline" size="sm" onClick={fetchTimeline}>
115→          Retry
116→        </Button>
117→      </div>
118→    );
119→  }
120→
121→  if (!items || items.length === 0) {
122→    return (
123→      <div className="flex items-center justify-center py-12 text-sm text-muted-foreground">
124→        No interactions yet
125→      </div>
126→    );
127→  }
128→
129→  return (
130→    <div className="flex flex-col gap-3">
131→      {items.map((item) => {
132→        const config = typeConfig[item.type] ?? defaultTypeConfig;
133→        const Icon = config.icon;
134→        return (
135→          <Card key={item.id} size="sm">
136→            <CardContent>
137→              <div className="flex items-start gap-3">
138→                <Badge variant={config.variant} className="mt-0.5 shrink-0 gap-1">
139→                  <Icon className="size-3" />
140→                  {config.label}
141→                </Badge>
142→                <div className="min-w-0 flex-1">
143→                  <div className="flex items-baseline gap-2 text-xs text-muted-foreground">
144→                    <span>{formatDate(item.createdAt)}</span>
145→                    {item.author && <span>— {item.author.name}</span>}
146→                  </div>
147→                  {item.subject && (
148→                    <p className="mt-0.5 text-sm font-medium truncate">
149→                      {item.subject}
150→                    </p>
151→                  )}
152→                  {item.content && (
153→                    <p className="mt-0.5 text-sm text-muted-foreground line-clamp-2">
154→                      {contentPreview(item.content)}
155→                    </p>
156→                  )}
157→                  {item.direction && (
158→                    <span className="mt-1 inline-block text-xs text-muted-foreground capitalize">
159→                      {item.direction}
160→                    </span>
161→                  )}
162→                </div>
163→              </div>
164→            </CardContent>
165→          </Card>
166→        );
167→      })}
168→    </div>
169→  );
170→}
