  1→"use client";
  2→
  3→import { History, ArrowRight, Loader2, AlertCircle } from "lucide-react";
  4→import { Card, CardContent } from "@/components/ui/card";
  5→import { Badge } from "@/components/ui/badge";
  6→import { Button } from "@/components/ui/button";
  7→import type { DealHistoryData } from "@/lib/api/types";
  8→
  9→interface DealHistoryTimelineProps {
 10→  history: DealHistoryData[] | null | undefined;
 11→  loading?: boolean;
 12→  error?: string | null;
 13→}
 14→
 15→function formatDate(dateStr: string | Date): string {
 16→  return new Intl.DateTimeFormat("en-US", {
 17→    month: "short",
 18→    day: "numeric",
 19→    year: "numeric",
 20→    hour: "numeric",
 21→    minute: "2-digit",
 22→  }).format(new Date(dateStr));
 23→}
 24→
 25→function getUserName(user: { firstName?: string | null; lastName?: string | null; email?: string | null } | null): string {
 26→  if (!user) return "Unknown";
 27→  if (user.firstName && user.lastName) {
 28→    return `${user.firstName} ${user.lastName}`;
 29→  }
 30→  if (user.firstName) return user.firstName;
 31→  if (user.email) return user.email;
 32→  return "Unknown";
 33→}
 34→
 35→export function DealHistoryTimeline({ history, loading = false, error = null }: DealHistoryTimelineProps) {
 36→  if (loading) {
 37→    return (
 38→      <div className="flex items-center justify-center py-12 text-muted-foreground">
 39→        <Loader2 className="mr-2 size-4 animate-spin" />
 40→        Loading history…
 41→      </div>
 42→    );
 43→  }
 44→
 45→  if (error) {
 46→    return (
 47→      <div className="flex flex-col items-center gap-3 py-12">
 48→        <div className="flex items-center gap-2 text-destructive">
 49→          <AlertCircle className="size-4" />
 50→          <span className="text-sm">{error}</span>
 51→        </div>
 52→        <Button variant="outline" size="sm">
 53→          Retry
 54→        </Button>
 55→      </div>
 56→    );
 57→  }
 58→
 59→  if (!history || history.length === 0) {
 60→    return (
 61→      <div className="flex items-center justify-center py-12 text-sm text-muted-foreground">
 62→        No history yet
 63→      </div>
 64→    );
 65→  }
 66→
 67→  return (
 68→    <div className="flex flex-col gap-3">
 69→      {history.map((item) => {
 70→        const fromStage = item.fromStage?.name ?? "Previous Stage";
 71→        const toStage = item.toStage?.name ?? "New Stage";
 72→        const changedBy = item.changedByUser ? getUserName(item.changedByUser) : "Unknown";
 73→
 74→        return (
 75→          <Card key={item.id} size="sm">
 76→            <CardContent>
 77→              <div className="flex items-start gap-3">
 78→                <Badge variant="outline" className="mt-0.5 shrink-0 gap-1">
 79→                  <History className="size-3" />
 80→                  Stage Change
 81→                </Badge>
 82→                <div className="min-w-0 flex-1">
 83→                  <div className="flex items-center gap-2 text-sm">
 84→                    <span className="font-medium">{fromStage}</span>
 85→                    <ArrowRight className="size-3 text-muted-foreground" />
 86→                    <span className="font-medium">{toStage}</span>
 87→                  </div>
 88→                  <div className="mt-1 flex items-baseline gap-2 text-xs text-muted-foreground">
 89→                    <span>{formatDate(item.changedAt)}</span>
 90→                    <span>— {changedBy}</span>
 91→                  </div>
 92→                  {item.comment && (
 93→                    <p className="mt-2 text-sm text-muted-foreground line-clamp-2">
 94→                      {item.comment}
 95→                    </p>
 96→                  )}
 97→                </div>
 98→              </div>
 99→            </CardContent>
100→          </Card>
101→        );
102→      })}
103→    </div>
104→  );
105→}
